public int highestEdgeScoreNode(int[] edges) {
    int[] scores = new int[edges.length];

    for (int i = 0; i < edges.length; i++) {
        scores[edges[i]] += i;
    }

    int maxIndex = 0;
    for (int i = 1; i < scores.length; i++) {
        if (scores[i] > scores[maxIndex]) {
            maxIndex = i;
        }
    }

    return maxIndex;
}
```

